import { z } from "zod";

export const PromptSchema = z.object({
  id: z.string().min(1),
  title: z.string().min(1, "Prompt title is required"),
  body: z.string().min(1, "Prompt body is required"),
  tags: z.array(z.string()).optional(),
  createdAt: z.string().optional(),
});

export const PortfolioSchema = z.object({
  slug: z
    .string()
    .min(1, "Slug is required")
    .regex(/^[a-z0-9-]+$/, "Slug must be lowercase alphanumeric with hyphens only"),
  title: z.string().min(1, "Portfolio title is required"),
  author: z.string().optional(),
  bio: z.string().optional(),
  prompts: z.array(PromptSchema).min(1, "At least one prompt is required"),
  createdAt: z.string(),
  updatedAt: z.string(),
});

export const ClaudeMessageSchema = z.object({
  uuid: z.string(),
  text: z.string(),
  sender: z.string(),
  created_at: z.string(),
  updated_at: z.string(),
});

export const ClaudeConversationSchema = z.object({
  uuid: z.string(),
  name: z.string(),
  created_at: z.string(),
  updated_at: z.string(),
  messages: z.array(ClaudeMessageSchema).optional(),
});

export const ClaudeExportSchema = z.object({
  conversations: z.array(ClaudeConversationSchema).optional(),
});

export const ExportPayloadSchema = z.object({
  slug: z.string().min(1, "Slug is required"),
});

export const OGImageQuerySchema = z.object({
  title: z.string().min(1),
  prompt: z.string().min(1),
});

export type Prompt = z.infer<typeof PromptSchema>;
export type Portfolio = z.infer<typeof PortfolioSchema>;
export type ClaudeExport = z.infer<typeof ClaudeExportSchema>;
export type ExportPayload = z.infer<typeof ExportPayloadSchema>;

export function OGImageTemplate({
  title,
  prompt,
  author,
}: {
  title: string;
  prompt: string;
  author?: string;
}) {
  const truncatedPrompt =
    prompt.length > 280 ? prompt.slice(0, 277) + "..." : prompt;

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        width: "1200px",
        height: "630px",
        background: "linear-gradient(135deg, #0a0a0f 0%, #1a1a2e 100%)",
        padding: "64px",
        fontFamily: "Inter, system-ui, sans-serif",
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          marginBottom: "40px",
        }}
      >
        <div
          style={{
            width: "12px",
            height: "12px",
            borderRadius: "50%",
            background: "#8b5cf6",
            marginRight: "12px",
          }}
        />
        <span
          style={{
            fontSize: "18px",
            fontWeight: 600,
            color: "#a09eb8",
            letterSpacing: "0.08em",
            textTransform: "uppercase",
          }}
        >
          Promptfolio
        </span>
      </div>

      <div
        style={{
          display: "flex",
          flexDirection: "column",
          flex: 1,
          justifyContent: "center",
        }}
      >
        <h1
          style={{
            fontSize: "56px",
            fontWeight: 800,
            color: "#e8e6f0",
            lineHeight: 1.15,
            marginBottom: "32px",
            letterSpacing: "-0.02em",
          }}
        >
          {title}
        </h1>
        <p
          style={{
            fontSize: "28px",
            color: "#a09eb8",
            lineHeight: 1.5,
            maxWidth: "960px",
          }}
        >
          {truncatedPrompt}
        </p>
      </div>

      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginTop: "auto",
        }}
      >
        {author ? (
          <span
            style={{
              fontSize: "20px",
              color: "#6e6c88",
              fontWeight: 500,
            }}
          >
            by {author}
          </span>
        ) : (
          <span />
        )}
        <span
          style={{
            fontSize: "18px",
            color: "#6e6c88",
            fontWeight: 400,
          }}
        >
          promptfolio.app
        </span>
      </div>
    </div>
  );
}

import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";

export function MarkdownRenderer({ children }: { children: string }) {
  return (
    <ReactMarkdown
      remarkPlugins={[remarkGfm]}
      components={{
        h1: ({ ...props }) => (
          <h1
            className="text-3xl font-display font-bold text-spotlight mb-6 mt-8"
            {...props}
          />
        ),
        h2: ({ ...props }) => (
          <h2
            className="text-2xl font-display font-semibold text-spotlight mb-4 mt-6"
            {...props}
          />
        ),
        h3: ({ ...props }) => (
          <h3
            className="text-xl font-display font-semibold text-spotlight mb-3 mt-5"
            {...props}
          />
        ),
        p: ({ ...props }) => (
          <p
            className="text-base leading-relaxed text-spotlight-muted mb-4"
            {...props}
          />
        ),
        code: ({ className, children, ...props }) => {
          const isInline = !className;
          return isInline ? (
            <code
              className="px-1.5 py-0.5 rounded-md bg-midnight-700 text-accent-glow text-sm font-mono"
              {...props}
            >
              {children}
            </code>
          ) : (
            <pre className="overflow-x-auto rounded-xl bg-midnight-800 border border-midnight-700 p-5 my-6">
              <code
                className="text-sm font-mono leading-relaxed text-spotlight"
                {...props}
              >
                {children}
              </code>
            </pre>
          );
        },
        ul: ({ ...props }) => (
          <ul
            className="list-disc pl-6 mb-4 text-spotlight-muted space-y-1"
            {...props}
          />
        ),
        ol: ({ ...props }) => (
          <ol
            className="list-decimal pl-6 mb-4 text-spotlight-muted space-y-1"
            {...props}
          />
        ),
        li: ({ ...props }) => <li className="leading-relaxed" {...props} />,
        blockquote: ({ ...props }) => (
          <blockquote
            className="border-l-4 border-accent pl-5 italic text-spotlight-dim my-6"
            {...props}
          />
        ),
        a: ({ ...props }) => (
          <a
            className="text-accent hover:text-accent-glow underline underline-offset-4 transition-colors"
            {...props}
          />
        ),
        hr: () => <hr className="border-midnight-700 my-8" />,
      }}
    >
      {children}
    </ReactMarkdown>
  );
}

